// CommentView is a view model for rendering a comment in the template
type CommentView struct {
	Author        string
	FormattedDate string
	SafeContent   template.HTML
}

type PageData struct {
	Comments []CommentView
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}

	tmpl, err := template.New("page").Parse(pageTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	var commentViews []CommentView
	for _, c := range comments {
		commentViews = append(commentViews, CommentView{
			Author:        c.Author,
			FormattedDate: c.CreatedAt.Format("January 2, 2006 at 3:04 PM"),
			SafeContent:   sanitizeHTML(c.Content),
		})
	}

	data := PageData{
		Comments: commentViews,
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := tmpl.Execute(w, data); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)
	println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}